function x256305_ProcEventEntry(varMap, varPlayer, varTalknpc, varQuest)	--点击该任务后执行此脚本
	if IsQuestHaveDone(varMap, varPlayer, x256305_var_QuestId) > 0 then
		return 
	end
	if IsHaveQuest(varMap,varPlayer, x256305_var_QuestId) > 0 then
			if x256305_CheckSubmit(varMap, varPlayer, varTalknpc) <= 0 then
						StartTalkTask(varMap)
						TalkAppendString(varMap,"#Y"..x256305_var_QuestName)
						TalkAppendString(varMap,x256305_var_ContinueInfo)
						StopTalkTask()
						DeliverTalkMenu(varMap, varPlayer, varTalknpc, x256305_var_FileId, x256305_var_QuestId);
			else
						StartTalkTask(varMap)
						TalkAppendString(varMap,"#Y"..x256305_var_QuestName)
						TalkAppendString(varMap,x256305_var_QuestCompleted)
						TalkAppendString(varMap," ")
						x256305_DispatchMissionInfo( varMap, varPlayer, varTalknpc )
						StopTalkTask()
						DeliverTalkContinueNM(varMap, varPlayer, varTalknpc, x256305_var_FileId, x256305_var_QuestId);
			end
  elseif x256305_ProcAcceptCheck(varMap, varPlayer, varTalknpc) > 0 then
			StartTalkTask(varMap)
	  	TalkAppendString(varMap,"#Y"..x256305_var_QuestName)
			TalkAppendString(varMap,x256305_var_QuestInfo)
			TalkAppendString( varMap,"#Y任务目标：")
			for i, item in x256305_var_ExtTarget do
					TalkAppendString( varMap,item.target)
			end 
			if x256305_var_QuestHelp ~= "" then
				TalkAppendString(varMap,"\n#G小提示:#W")
				TalkAppendString(varMap,x256305_var_QuestHelp )
			end
			x256305_DispatchMissionInfo( varMap, varPlayer, varTalknpc )
	  	StopTalkTask()
			DeliverTalkInfoNM(varMap, varPlayer, varTalknpc, x256305_var_FileId, x256305_var_QuestId);
  end
	
end
