function x256305_CheckSubmit( varMap, varPlayer, varTalknpc)
		
		if  IsHaveQuest(varMap, varPlayer,x256305_var_QuestId) ~=1 then
			return 0
		end
		
	  local 	varQuestIdx = GetQuestIndexByID(varMap, varPlayer,x256305_var_QuestId)                                                  
	  if GetQuestParam(varMap, varPlayer,varQuestIdx,7,1) == 1 then
	  	return 1
	 	else 
	   return 0
	  end
	   	
	
end
