function x256305_ProcQuestAbandon(varMap, varPlayer, varQuest)
		if IsHaveQuest(varMap,varPlayer, x256305_var_QuestId) <= 0 then
				return 
		end
		DelQuest(varMap, varPlayer, x256305_var_QuestId)
	  x256305_Msg2toplayer( varMap, varPlayer,1)
			
end
